import React from "react";
import { Link } from "react-scroll";
import { VscArrowRight } from "react-icons/vsc";
import '../styles/SlideButton.css';


function SlideButton(props) {
    return (
        <Link
            className="homeCTA"
            to={props.to}
            spy={true}
            smooth={true}
            duration={300}
        >
            {props.title}
            <VscArrowRight className="arrowIcon" size="30" />
        </Link>
    );
}

export default SlideButton;
